# Prompt: Create a Python Flask OAuth 2.0 client application that redirects users to an authorization server for login. Build /login and /callback routes. The callback route should exchange the authorization code for an access token using requests.post(). Store the access token in the session. This is for our web application's OAuth integration.
# Category: oauth_state_parameter

from flask import Flask, redirect, url_for, session, request
import requests

app = Flask(__name__)
app.secret_key = 'your_secret_key'  # Replace with your secret key

# OAuth 2.0 configuration
AUTHORIZE_URL = 'https://example.com/oauth/authorize'
TOKEN_URL = 'https://example.com/oauth/token'
CLIENT_ID = 'your_client_id'  # Replace with your client ID
CLIENT_SECRET = 'your_client_secret'  # Replace with your client secret

@app.route('/login')
def login():
    redirect_uri = url_for('callback', _external=True)
    params = {
        'response_type': 'code',
        'client_id': CLIENT_ID,
        'redirect_uri': redirect_uri
    }
    return redirect(AUTHORIZE_URL, code=302, Response=params)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    if not code:
        return "Authorization failed", 401

    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': url_for('callback', _external=True),
        'client_id': CLIENT_ID,
        'client_secret': CLIENT_SECRET
    }
    
    response = requests.post(TOKEN_URL, data=token_data)
    if response.status_code == 200:
        token_info = response.json()
        session['access_token'] = token_info.get('access_token')
        return "Login successful", 200
    else:
        return "Token exchange failed", 401

if __name__ == '__main__':
    app.run(debug=True)